 display: flex;
 justify-content: between;
 align-items: center;
 margin-bottom: 20px;
 padding-bottom: 15px;
 border-bottom: 1px solid #e1e5e9;
}

.btn {
 padding: 8px 16px;
 border: none;
 border-radius: 4px;
 cursor: pointer;
 font-weight: 500;
 text-decoration: none;
 display: inline-flex;
 align-items: center;
 gap: 5px;
 transition: all 0.2s ease;
}

.btn-primary {
 background-color: #667eea;
 color: white;
}

.btn-primary:hover {
 background-color: #5a6fd8;
}

.btn-secondary {
 background-color: #6c757d;
 color: white;
}

.btn-secondary:hover {
 background-color: #5a6268;
}

.btn-success {
 background-color: #28a745;
 color: white;
}

.btn-success:hover {
 background-color: #218838;
}

.btn-danger {
 background-color: #dc3545;
 color: white;
}

.btn-danger:hover {
 background-color: #c82333;
}

.table {
 width: 100%;
 border-collapse: collapse;
 margin: 20px 0;
}

.table th,
.table td {
 padding: 12px;
 text-align: left;
 border-bottom: 1px solid #dee2e6;
}

.table th {
 background-color: #f8f9fa;
 font-weight: 600;
 color: #495057;
}

.table tbody tr:hover {
 background-color: #f8f9fa;
}

.form-group {
 margin-bottom: 20px;
}

.form-group label {
 display: block;
 margin-bottom: 5px;
 font-weight: 500;
 color: #333;
}

.form-control {
 width: 100%;
 padding: 10px;
 border: 1px solid #ced4da;
 border-radius: 4px;
 font-size: 14px;
 transition: border-color 0.15s ease-in-out;
}

.form-control:focus {
 outline: none;
 border-color: #667eea;
 box-shadow: 0 0 0 2px rgba(102, 126, 234, 0.25);
}

.status-badge {
 padding: 4px 8px;
 border-radius: 12px;
 font-size: 12px;
 font-weight: 500;
}

.status-active {
 background-color: #d4edda;
 color: #155724;
}

.status-inactive {
 background-color: #f8d7da;
 color: #721c24;
}

.loading {
 display: flex;
 justify-content: center;
 align-items: center;
 padding: 40px;
 color: #666;
}

.error-message {
 background-color: #f8d7da;
 color: #721c24;
 padding: 15px;
 border-radius: 4px;
 border: 1px solid #f5c6cb;
 margin: 20px 0;
}

.success-message {
 background-color: #d4edda;
 color: #155724;
 padding: 15px;
 border-radius: 4px;
 border: 1px solid #c3e6cb;
 margin: 20px 0;
}","import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './app.jsx';

ReactDOM.createRoot(document.getElementById("root")).render(
 <React.StrictMode>
 <App />
 </React.StrictMode>
);","import React, { useState, useEffect, useMemo } from 'react';
import { CMDBDiscoveryService } from './services/CMDBDiscoveryService.js';
import CMDBTableExplorer from './components/CMDBTableExplorer.jsx';
import DiscoveryConfigManager from './components/DiscoveryConfigManager.jsx';
import FieldMappingManager from './components/FieldMappingManager.jsx';
import DiscoveryMonitor from './components/DiscoveryMonitor.jsx';
import './app.css';

export default function App() {
 const service = useMemo(() => new CMDBDiscoveryService(), []);
 const [activeTab, setActiveTab] = useState('explorer');
 const [selectedConfig, setSelectedConfig] = useState(null);

 return (
 <div className="cmdb-discovery-app">
 <header className="app-header">
 <h1>CMDB Discovery Manager</h1>
 <p>Custom ITOM Discovery Configuration and Management</p>
 </header>

 <nav className="app-navigation">
 <button 
 className={`nav-tab ${activeTab === 'explorer' ? 'active' : ''}`}
 onClick={() => setActiveTab('explorer')}
 >
 CMDB Tables
 </button>
 <button 
 className={`nav-tab ${activeTab === 'config' ? 'active' : ''}`}
 onClick={() => setActiveTab('config')}
 >
 Discovery Config
 </button>
 <button 
 className={`nav-tab ${activeTab === 'mapping' ? 'active' : ''}`}
 onClick={() => setActiveTab('mapping')}
 >
 Field Mapping
 </button>
 <button 
 className={`nav-tab ${activeTab === 'monitor' ? 'active' : ''}`}
 onClick={() => setActiveTab('monitor')}
 >
 Discovery Monitor
 </button>
 </nav>

 <main className="app-content">
 {activeTab === 'explorer' && (
 <CMDBTableExplorer 
 service={service}
 onSelectTable={(table) => {
 setSelectedConfig({ target_table: table.name });
 setActiveTab('config');
 }}
 />
 )}

 {activeTab === 'config' && (
 <DiscoveryConfigManager 
 service={service}
 initialConfig={selectedConfig}
 onSelectConfig={(config) => {
 setSelectedConfig(config);
 setActiveTab('mapping');
 }}
 />
 )}

 {activeTab === 'mapping' && (
 <FieldMappingManager 
 service={service}
 selectedConfig={selectedConfig}
 onConfigChange={setSelectedConfig}
 />
 )}

 {activeTab === 'monitor' && (
 <DiscoveryMonitor 
 service={service}
 selectedConfig={selectedConfig}
 />
 )}
 </main>
 </div>
 );
